(function () {
    'use strict';

    // 类
    class Person {
        // 构造函数
        constructor(name, age) {
            // 定义类的属性 name, age
            this.name = name;
            this.age = age;
        }

        // 类方法
        hello() {
            return `hello: ${this.name} ${this.age}`;
        }

        // getter 和 setter
        // 约定 getter/setter 名字的前面加 “_” 为类的私有变量
        // getter 不可单独出现，setter 可以单独出现
        // getter 与 setter 必须同级出现（不能一个在基类，一个在子类）
        get nickname() {
            return this._nickname;
        }
        set nickname(val) {
            this._nickname = val;
        }
    }

    // 基类
    class Life {
        constructor(name) {
            console.log("super class");
            this.name = name;
        }

        hello() {
            return "hello: " + this.name;
        }
    }

    // 子类
    class Person$1 extends Life {
        constructor(name, age) {
            // 调用基类构造函数
            super(name);

            console.log("sub class");
            this.age = age;
        }

        // 重写基类方法（如果需要调用基类方法，则调用 super.hello() 即可）
        hello() {
            return `hello: ${this.name} ${this.age} ${super.hello()}`;
        }
    }

    // 基类
    class Life$1 {
        // 静态方法
        static getName() {
            return "super";
        }
        static hello() {
            return "hello: " + this.getName();
        }
    }

    // 子类
    class Person$2 extends Life$1 {
        static hello() {
            return `hello: sub ${super.hello()}`;
        }
    }

    /**
     * 本例用于演示类与继承
     * es6 暂时无接口，静态属性
     */

    function Person$3(name, age) {
        this.name = name;
        this.age = age;
    }
    Person$3.prototype.hello = function () {
        return `hello: ${this.name} ${this.age}`;
    };
    let obj = new Person$3("webabcd", 40);
    console.log(`${obj.hello()} ${obj.name} ${obj.age}`);
    Person.prototype.hello2 = function() {
        return "hello2: " + this.name;
    };
    Object.assign(Person.prototype,{
        hello3:function() {
            return "hello3: " + this.name;
        },
        hello4:function() {
            return "hello4: " + this.name;
        }
    });
    Person.prototype.prop1 = "abc";
    let obj_a = new Person("webabcd", 40);
    obj_a.nickname = "wanglei";
    console.log(`${obj_a.hello()} ${obj_a.name} ${obj_a.age} ${obj_a.hello2()} ${obj_a.hello3()} ${obj_a.hello4()} ${obj_a.nickname} ${obj_a.prop1}`);
    let obj_b = new Person$1("webabcd", 40);
    console.log(obj_b.hello());
    Person$2.prop1 = "abc";
    Person$2.prop2 = 100;
    console.log(`${Person$2.prop1} ${Person$2.prop2} ${Person$2.hello()} ${Person$2.name}`);

}());
